SELECT count(*) FROM movie_companies, title, company_name, movie_info, company_type, cast_info, info_type, name, movie_keyword WHERE movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_info.movie_id = title.id AND movie_companies.company_type_id = company_type.id AND cast_info.movie_id = title.id AND movie_info.info_type_id = info_type.id AND cast_info.person_id = name.id AND movie_keyword.movie_id = title.id;